module RefModule(
  input [31:0] input_data,
  output reg [15:0] output_sum
);reg [15:0] lower_bits_twos_comp;
  reg [15:0] upper_bits_twos_comp;
  reg [15:0] sum;

    wire _n01 = ~input_data[15:0][0] ^ 1[0];
  wire _c01 = ~input_data[15:0][0] & 1[0];
  wire _n02 = ~input_data[15:0][1] ^ 1[1] ^ _c01;
  wire _c02 = (~input_data[15:0][1] & 1[1]) | (~input_data[15:0][1] & _c01) | (1[1] & _c01);
  wire _n03 = ~input_data[15:0][2] ^ 1[2] ^ _c02;
  wire _c03 = (~input_data[15:0][2] & 1[2]) | (~input_data[15:0][2] & _c02) | (1[2] & _c02);
  wire _n04 = ~input_data[15:0][3] ^ 1[3] ^ _c03;
  wire _c04 = (~input_data[15:0][3] & 1[3]) | (~input_data[15:0][3] & _c03) | (1[3] & _c03);
  assign lower_bits_twos_comp = {_n01, _n02, _n03, _n04};
  assign upper_bits_twos_comp = ~input_data[31:16] + 1;

  always @(*) begin
    sum = lower_bits_twos_comp + upper_bits_twos_comp;
    if (sum > 32767) begin
      output_sum = 32767;
    end else begin
      output_sum = sum;
    end
  end

endmodule
